// API Key authentication check - timing-safe comparison
const headers = $input.first().json.headers || {};

// Case-insensitive header lookup (defense against platform normalization changes)
const headerKeys = Object.keys(headers);
const apiKeyHeader = headerKeys.find(k => k.toLowerCase() === 'x-api-key');
const providedKeyRaw = apiKeyHeader !== undefined ? headers[apiKeyHeader] : '';
const expectedKey = $env.EMBEDDINGS_API_KEY;

const MAX_LEN = 256;

// Timing-safe comparison - prevents timing attacks on API key
function timingSafeEqual(a, b) {
  if (typeof a !== 'string' || typeof b !== 'string') return false;

  // Include bounds check in result (constant-time, no branch)
  let result = (a.length > MAX_LEN || b.length > MAX_LEN) ? 1 : 0;
  // Constant-time comparison: always iterate MAX_LEN, use 0 for out-of-bounds
  for (let i = 0; i < MAX_LEN; i++) {
    const charA = i < a.length ? a.charCodeAt(i) : 0;
    const charB = i < b.length ? b.charCodeAt(i) : 0;
    result |= charA ^ charB;
  }
  // Include length check in constant-time result
  result |= (a.length === b.length) ? 0 : 1;
  return result === 0;
}

// Authentication logic:
// - If server has expectedKey configured: client MUST provide matching key
// - If server has NO expectedKey configured: reject any request that provides a key
// - If neither configured: allow (no auth required)
if ((expectedKey || providedKeyRaw) && !timingSafeEqual(providedKeyRaw || '', expectedKey || '')) {
  return [{ json: { valid: false, error: 'Authentication failed' } }];
}

const input = $input.first().json || {};

// === TYPE VALIDATION ===
if (input.text !== undefined && typeof input.text !== 'string') {
  return [{ json: { valid: false, error: 'Invalid text: must be a string' } }];
}
if (input.model !== undefined && typeof input.model !== 'string') {
  return [{ json: { valid: false, error: 'Invalid model: must be a string' } }];
}
if (input.channel !== undefined && typeof input.channel !== 'string') {
  return [{ json: { valid: false, error: 'Invalid channel: must be a string' } }];
}

const text = (input.text || input.message || '').toString().trim();
const model = (input.model || 'all-MiniLM-L6-v2').toString().trim();
const channelRaw = (input.channel || 'general').replace(/^#+/, '').replace(/[<>@&]/g, '').slice(0, 100);

// === TEXT VALIDATION ===
if (!text) {
  return [{ json: { valid: false, error: 'Missing required field: text (or message)' } }];
}
if (text.length > 32768) {
  return [{ json: { valid: false, error: 'Text too long: max 32768 characters' } }];
}

// === MODEL VALIDATION ===
if (model.length > 100) {
  return [{ json: { valid: false, error: 'Model name too long: max 100 characters' } }];
}
if (!model.match(/^[a-zA-Z0-9_\-\/\.]+$/)) {
  return [{ json: { valid: false, error: 'Invalid model: must be alphanumeric with dashes, underscores, slashes, or dots' } }];
}

// === CHANNEL VALIDATION ===
if (!channelRaw.match(/^[a-zA-Z0-9_-]+$/)) {
  return [{ json: { valid: false, error: 'Invalid channel: must be alphanumeric, dash, or underscore only' } }];
}

return [{
  json: {
    valid: true,
    text: text,
    model: model,
    channel: channelRaw
  }
}];

// Process embeddings response
const body = $input.first().json || {};
const validatedInput = $('Validate Input').first().json || {};
const embeddings = body.data || [];
const firstEmbedding = embeddings[0]?.embedding || [];
const usage = body.usage || {};

return [{
  json: {
    success: embeddings.length > 0,
    embedding_dim: firstEmbedding.length,
    total_embeddings: embeddings.length,
    tokens_used: usage.total_tokens || 0,
    model: validatedInput.model || 'unknown',
    channel: validatedInput.channel || 'general',
    timestamp: new Date().toISOString()
  },
  binary: {
    embedding: {
      data: Buffer.from(JSON.stringify(firstEmbedding)),
      mimeType: 'application/json'
    }
  }
}];
